const express      = require('express');
const router       = express.Router();
const Registration = require('../models/Registration');
const Event        = require('../models/Event');
const Announcement = require('../models/Announcement');
const User         = require('../models/User');
const nodemailer   = require('nodemailer');

/* ── COLLEGE LOGO (Banasthali Vidyapith) embedded as base64 ── */
const COLLEGE_LOGO_DATA_URL = "data:image/jpeg;base64,";

/* ══════════════════════════════════════════════════════════
   MIDDLEWARE
══════════════════════════════════════════════════════════ */
async function requireTechTeam(req, res, next) {
  const userId = req.headers['x-user-id'];
  if (!userId) return res.status(401).json({ message: 'Not authenticated.' });
  try {
    const user = await User.findById(userId).select('-password');
    if (!user || (user.role !== 'admin' && (user.role !== 'team' || user.team !== 'tech'))) {
      return res.status(403).json({ message: 'Access restricted to Tech team or Admin users.' });
    }
    req.currentUser = user;
    next();
  } catch {
    return res.status(401).json({ message: 'Invalid session.' });
  }
}

const transporter = nodemailer.createTransport({
  service: 'gmail',
  auth: { user: process.env.EMAIL_USER, pass: process.env.EMAIL_PASS },
});

/* ══════════════════════════════════════════════════════════
   STATS
══════════════════════════════════════════════════════════ */
router.get('/stats', requireTechTeam, async (req, res) => {
  try {
    const [totalStudents, totalEvents, certsSent, pending] = await Promise.all([
      Registration.countDocuments(),
      Event.countDocuments(),
      Registration.countDocuments({ certificateSent: true }),
      Registration.countDocuments({ paymentStatus: 'screenshot_uploaded' }),
    ]);
    res.json({ totalStudents, totalEvents, certsSent, pending });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

/* ══════════════════════════════════════════════════════════
   REGISTRATIONS
══════════════════════════════════════════════════════════ */
router.get('/registrations', requireTechTeam, async (req, res) => {
  try {
    const { event, status, search, page = 1, limit = 30 } = req.query;
    const filter = {};
    if (event)  filter.eventName = { $regex: event, $options: 'i' };
    if (status) filter.status    = status;
    if (search) filter.$or = [
      { name:  { $regex: search, $options: 'i' } },
      { email: { $regex: search, $options: 'i' } },
    ];
    const [registrations, total] = await Promise.all([
      Registration.find(filter).sort({ createdAt: -1 }).skip((page-1)*limit).limit(Number(limit)).lean(),
      Registration.countDocuments(filter),
    ]);
    const students = registrations.map(r => ({
      _id: r._id, name: r.name, email: r.email, course: r.course,
      year: r.year, branch: r.branch, phone_number: r.phone,
      teamName: r.teamName, status: r.status,
      events: [r.eventName],
      certificates: r.certificateSent ? [r.eventName] : [],
      createdAt: r.createdAt,
    }));
    res.json({ students, total, page: Number(page), pages: Math.ceil(total/limit) });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

router.get('/registrations/events-summary', requireTechTeam, async (req, res) => {
  try {
    const summary = await Registration.aggregate([
      { $group: { _id: '$eventName', count: { $sum: 1 }, confirmed: { $sum: { $cond: [{ $eq: ['$status','confirmed'] }, 1, 0] } }, pending: { $sum: { $cond: [{ $eq: ['$status','pending'] }, 1, 0] } } } },
      { $sort: { count: -1 } },
    ]);
    res.json(summary);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

router.patch('/registrations/:id/status', requireTechTeam, async (req, res) => {
  try {
    const { status } = req.body;
    if (!['pending','confirmed','rejected'].includes(status))
      return res.status(400).json({ message: 'Invalid status.' });
    const reg = await Registration.findByIdAndUpdate(req.params.id, { status }, { new: true });
    if (!reg) return res.status(404).json({ message: 'Registration not found.' });
    res.json({ message: 'Status updated.', registration: reg });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

/* ══════════════════════════════════════════════════════════
   EMAIL
══════════════════════════════════════════════════════════ */
router.post('/email/send', requireTechTeam, async (req, res) => {
  try {
    const { to, subject, body, eventFilter } = req.body;
    let recipients = to || [];
    if (!recipients.length && eventFilter) {
      const regs = await Registration.find({ eventName: eventFilter }).select('email').lean();
      recipients = regs.map(r => r.email);
    }
    if (!recipients.length) return res.status(400).json({ message: 'No recipients specified.' });
    if (!subject || !body) return res.status(400).json({ message: 'subject and body are required.' });
    await transporter.sendMail({
      from: `"ClustrCore" <${process.env.EMAIL_USER}>`,
      bcc: recipients, subject,
      html: `<div style="font-family:sans-serif;max-width:600px;margin:auto;padding:32px;background:#f9f9f9;border-radius:12px"><h2 style="color:#3a6bc8;margin-bottom:8px">ClustrCore</h2><hr style="border:none;border-top:1px solid #ddd;margin-bottom:24px"><div style="color:#333;line-height:1.7;font-size:15px">${body.replace(/\n/g,'<br>')}</div><hr style="border:none;border-top:1px solid #ddd;margin-top:24px"><p style="color:#999;font-size:12px;margin-top:12px">This email was sent from ClustrCore. Do not reply to this email.</p></div>`,
    });
    res.json({ message: `Email sent to ${recipients.length} recipient(s).`, count: recipients.length });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

/* ══════════════════════════════════════════════════════════
   CERTIFICATES
   ✅ Only sends to registrations where attended === true
   ✅ Checks that event status is 'completed' before allowing bulk send
══════════════════════════════════════════════════════════ */
router.post('/certificates/send', requireTechTeam, async (req, res) => {
  try {
    const { studentId, eventName } = req.body;
    if (!studentId || !eventName)
      return res.status(400).json({ message: 'studentId and eventName are required.' });

    const reg = await Registration.findById(studentId).populate('event');
    if (!reg) return res.status(404).json({ message: 'Registration not found.' });

    /* ✅ Only send if the student attended */
    if (reg.status !== 'attended')
      return res.status(400).json({ message: `${reg.name} is not marked as attended. Mark attendance first.` });

    /* ✅ Event check removed - certificates can be issued anytime after attendance */

    const certSVG    = generateCertSVG(reg.name, eventName);
    const certBuffer = Buffer.from(certSVG, 'utf-8');

    await transporter.sendMail({
      from:    `"ClustrCore" <${process.env.EMAIL_USER}>`,
      to:      reg.email,
      subject: `Your Certificate of Participation — ${eventName}`,
      html: `<div style="font-family:sans-serif;max-width:600px;margin:auto;padding:32px;background:#f9f9f9;border-radius:12px"><h2 style="color:#3a6bc8">Congratulations, ${reg.name}! 🎉</h2><p style="color:#555;line-height:1.7;font-size:15px">Thank you for attending <strong>${eventName}</strong>.<br>Please find your certificate of participation attached.</p><p style="color:#999;font-size:12px;margin-top:24px">— ClustrCore Team</p></div>`,
      attachments: [{
        filename:    `Certificate_${reg.name.replace(/\s+/g,'_')}_${eventName.replace(/\s+/g,'_')}.svg`,
        content:     certBuffer,
        contentType: 'image/svg+xml',
      }],
    });

    await Registration.findByIdAndUpdate(studentId, { certificateSent: true });
    res.json({ message: `Certificate sent to ${reg.email}` });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

router.post('/certificates/send-bulk', requireTechTeam, async (req, res) => {
  try {
    const { eventName } = req.body;
    if (!eventName) return res.status(400).json({ message: 'eventName is required.' });

    /* ✅ Event check removed - certificates can be issued anytime after attendance */

    /* ✅ Only registrations where status = 'attended' */
    const regs = await Registration.find({ eventName, status: 'attended' });
    if (!regs.length)
      return res.status(404).json({ message: 'No attended registrations found for this event. Mark attendance first.' });

    const results = { sent: [], failed: [], skipped: [] };

    for (const reg of regs) {
      try {
        const certSVG    = generateCertSVG(reg.name, eventName);
        const certBuffer = Buffer.from(certSVG, 'utf-8');
        await transporter.sendMail({
          from:    `"ClustrCore" <${process.env.EMAIL_USER}>`,
          to:      reg.email,
          subject: `Your Certificate of Participation — ${eventName}`,
          html:    `<div style="font-family:sans-serif;max-width:600px;margin:auto;padding:32px;background:#f9f9f9;border-radius:12px"><h2 style="color:#3a6bc8">Congratulations, ${reg.name}! 🎉</h2><p style="color:#555;line-height:1.7">Thank you for attending <strong>${eventName}</strong>. Your certificate is attached.</p><p style="color:#999;font-size:12px;margin-top:24px">— ClustrCore Team</p></div>`,
          attachments: [{
            filename:    `Certificate_${reg.name.replace(/\s+/g,'_')}.svg`,
            content:     certBuffer,
            contentType: 'image/svg+xml',
          }],
        });
        await Registration.findByIdAndUpdate(reg._id, { certificateSent: true });
        results.sent.push(reg.email);
      } catch {
        results.failed.push(reg.email);
      }
    }

    res.json({
      message: `Sent ${results.sent.length}/${regs.length} certificates to attended participants.`,
      ...results,
    });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

